using NP std;
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
        a=a*a;
		b>>=1;
	}
	return ans;
}
CI MAXN=1e5+5;
int n,m,sum[MAXN<<2],rev[MAXN<<2];
char ch;
void pushdown(int len,int i)
{ 
    sum[i]=len-sum[i];
    rev[i]^=true;
}
void pushup(int i)
{
    sum[i]=sum[i<<1]+sum[i<<1|1];
}
void push_down(int l,int r,int i)
{
    if(rev[i])
	{
        pushdown(l,i<<1);
        pushdown(r,i<<1|1);
        rev[i]=false;
    }
}
void build(int l,int r,int i)
{
    if(l==r)
	{
        cin>>ch;
        sum[i]=ch-'0';
        return;
    }
    int mid=(l+r)>> 1;
    build(l,mid,i<<1);
    build(mid+1,r,i<<1|1);
    pushup(i);
}
void upartd(int s,int e,int l=1,int r=n,int i=1)
{
    if(s<=l&&r<=e)
	{
        pushdown(r-l+1,i);
        return;
    }
    int mid=(l+r)>>1;
    push_down(mid-l+1,r-mid,i);//push_down(mid-l+1,r+mid,i);
    if(s<=mid)//<
        upartd(s,e,l,mid,i<<1);
    if(e>mid)
        upartd(s,e,mid+1,r,i<<1|1);
    pushup(i);
}
int query(int s,int e,int l=1,int r=n,int i=1)
{
    if(s<=l&&r<=e)return sum[i];
    int mid=(l+r)>>1;
    push_down(mid-l+1,r-mid,i);//push_down(mid-l+1,r+mid,i);
    int ans=0;
    if(s<=mid)//<
        ans+=query(s,e,l,mid,i<<1);
    if(e>mid)
        ans+=query(s,e,mid+1,r,i<<1|1);
    return ans;
}
signed main(void)
{
    IOS
    cin>>n>>m;
    wh(m--)
	{
		int cmd,l,r;
        cin>>cmd>>l>>r;
        if(cmd==0)
		{
			upartd(l,r);
		}
        else
		{
			cout<<query(l,r)<<'\n';
		}
    }
    return false;
}
